# include <bits/stdc++.h>
using namespace std;
int n, w, a[20], b[20], ans = 25;
void dfs (int t, int s) {
	if (t>= ans)
		return ;
	if (s >= n) {
		ans = t;
		return ;
	}
	for (int i = 0; i < t; ++ i)
		if (b[i] + a[s] <= w) {
			b[i] += a[s];
			dfs (t, s + 1);
			b[i] -= a[s];
		}
	b[t] = a[s];
	dfs (t + 1, s + 1);
	b[t] = 0;
	return ;
}
int main () {
	cin >> n >> w;
	for (int i = 0; i < n; ++ i)
		cin >> a[i];
	sort (a, a + n, greater <int> ());
	dfs (0, 0);
	cout << ans;
	return 0;
}
